using Microsoft.Extensions.Logging;
using SkiaSharp.Views.Maui.Controls.Hosting;

namespace Repro;

public static class MauiProgram
{
	public static MauiApp CreateMauiApp()
	{
		var builder = MauiApp.CreateBuilder();
		builder
			.UseMauiApp<App>()
			.UseSkiaSharp()
			.ConfigureFonts(fonts =>
			{
				fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
			});
		return builder.Build();
	}
}

using SkiaSharp;
using SkiaSharp.Views.Maui;

namespace Repro;

public partial class MainPage : ContentPage
{
    private int _glPaintCount;
    private int _canvasPaintCount;

    public MainPage() => InitializeComponent();

    private void OnGLPaintSurface(object sender, SKPaintGLSurfaceEventArgs e)
    {
        _glPaintCount++;
        bool isMainThread = MainThread.IsMainThread;
        int threadId = Environment.CurrentManagedThreadId;
        System.Diagnostics.Debug.WriteLine(
            $"[SKGLView] PaintSurface #{_glPaintCount}: IsMainThread={isMainThread}, ThreadId={threadId}");
        var canvas = e.Surface.Canvas;
        canvas.Clear(isMainThread ? SKColors.Green : SKColors.Red);
    }

    private void OnCanvasPaintSurface(object sender, SKPaintSurfaceEventArgs e)
    {
        _canvasPaintCount++;
        bool isMainThread = MainThread.IsMainThread;
        int threadId = Environment.CurrentManagedThreadId;
        System.Diagnostics.Debug.WriteLine(
            $"[SKCanvasView] PaintSurface #{_canvasPaintCount}: IsMainThread={isMainThread}, ThreadId={threadId}");
        var canvas = e.Surface.Canvas;
        canvas.Clear(isMainThread ? SKColors.Green : SKColors.Red);
    }
}
